import React from 'react';
import {Card, CardContent, Button} from 'react-bootstrap';

const RehabService = () => {
  return (
    <div className="bg-gray-100 min-h-screen">
      {/* Header */}
      <header className="bg-white shadow-md">
        <div className="container mx-auto flex items-center justify-between py-4 px-6">
          <h1 className="text-2xl font-bold">AiBLE</h1>
          <div className="flex space-x-4">
            <a href="#" className="text-gray-600 hover:text-black">프로그램</a>
            <a href="#" className="text-gray-600 hover:text-black">나의 운동</a>
            <a href="#" className="text-gray-600 hover:text-black">커뮤니티</a>
            <div className="relative">
              <input placeholder="운동 분석, 맞춤 커리큘럼 찾기" className="w-64" />
            </div>
          </div>
        </div>
      </header>

      {/* Hero Section */}
      <div className="bg-yellow-400 text-white py-4 px-6">
        <div className="container mx-auto flex justify-between items-center">
          <span>[OOOO] 신청 오픈</span>
          <Button className="bg-white text-yellow-400">신청하기</Button>
        </div>
      </div>

      {/* Main Content */}
      <main className="container mx-auto py-10 px-6">
        <div className="grid md:grid-cols-2 gap-6 mb-10">
          {/* Self-rehabilitation program */}
          <Card className="relative">
            <img src="/images/rehab_program.jpg" alt="재활 프로그램" className="w-full h-48 object-cover rounded-t-md" />
            <p className="p-4">
              <h2 className="text-xl font-bold">자가 재활 프로그램</h2>
              <p className="text-gray-700 mt-2">
                AI 맞춤 피드백으로 스스로 관리하는 스마트 재활! 개인별 운동 데이터 분석으로 효과적인 회복을 경험하세요.
              </p>
              <div className="text-right mt-4">
                <span className="text-lg font-bold">12,000원/월</span>
              </div>
            </p>
          </Card>

          {/* Game-based rehab content */}
          <Card className="relative">
            <img src="/images/rehab_game.jpg" alt="재활 게임 콘텐츠" className="w-full h-48 object-cover rounded-t-md" />
            <p className="p-4">
              <h2 className="text-xl font-bold">자가 재활 게임 콘텐츠</h2>
              <p className="text-gray-700 mt-2">
                지루한 재활은 그만! 게임처럼 즐기는 재미있는 재활 치료. 몰입감 있는 콘텐츠로 운동 지속력을 높여보세요.
              </p>
            </p>
          </Card>
        </div>

        {/* Recommended Curriculums */}
        <h3 className="text-2xl font-bold mb-6">추천 커리큘럼</h3>
        <div className="grid sm:grid-cols-2 md:grid-cols-4 gap-4">
          {["#고관절 스트레칭", "#상체 관절 운동", "#균형 감각 강화", "#하체 근력 운동 Basic", "#고관절 스트레칭"].map((title, index) => (
            <Card key={index} className="relative">
              <img
                src={`/images/curriculum_${index + 1}.jpg`}
                alt={title}
                className="w-full h-32 object-cover rounded-t-md"
              />
              <p className="p-4">
                <h4 className="text-lg font-bold">{title}</h4>
                <p className="text-gray-600 mt-2">5개 커리큘럼</p>
              </p>
            </Card>
          ))}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-gray-200 py-6 mt-10">
        <div className="container mx-auto grid md:grid-cols-4 gap-6 text-sm text-gray-700">
          <div>
            <h5 className="font-bold mb-3">고객센터</h5>
            <p>오전 10시 ~ 오후 6시 (주말, 공휴일 제외)</p>
            <Button className="mt-4 bg-yellow-400 text-white">문의하기</Button>
          </div>
          <div>
            <h5 className="font-bold mb-3">정책</h5>
            <ul>
              <li>이용약관</li>
              <li>개인정보 처리방침</li>
            </ul>
          </div>
          <div>
            <h5 className="font-bold mb-3">지원</h5>
            <ul>
              <li>도움말</li>
              <li>기부 프로그램</li>
            </ul>
          </div>
          <div>
            <h5 className="font-bold mb-3">기타</h5>
            <ul>
              <li>회사 정보 확인</li>
              <li>채용</li>
            </ul>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default RehabService;