import { useState } from "react";
import axios from "axios";

export default function Survey(){
  let [step, setStep] = useState(0)
  // 입력값 상태 관리
  const [formData, setFormData] = useState({
  id: "",
    gender: "",
    age: "",
    smoking:"",
    smoking_avg:"",
    exercise: "",
    exercise_freq: "",
    disability: "",
    comments: "",
  });
  function nextStep(){
    setStep(step+1);
  }
  function prevStep(){
    setStep(step-1);
  }
  // 입력값 변경 핸들러
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // 폼 제출 핸들러
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post("http://localhost:8000/survey", formData);
      console.log("응답 데이터:", response.data);
      alert("설문이 제출되었습니다!");
    } catch (error) {
      console.error("설문 제출 오류:", error);
      alert("설문 제출에 실패했습니다.");
    }
  };

  return (
    <div className="p-4 max-w-md mx-auto border rounded-lg shadow-md">
      <h2 className="text-xl font-bold mb-4">설문 조사</h2>
      <form onSubmit={handleSubmit} className="flex flex-col space-y-3">
      {
        step==0 && 
        <div className="form-section">
          <h2>기본 정보</h2>
          <label htmlFor="id">아이디:</label>
          <input type="text" id="id" name="id" value={formData.id} onChange={handleChange} required />
          <label htmlFor="gender">성별:</label>
          <input type="text" id="gender" name="gender" value={formData.gender} onChange={handleChange} required />

          <label htmlFor="age">연령:</label>
          <input type="number" id="age" name="age" value={formData.age} onChange={handleChange} required />
        </div>
      }
      {
        step==1 &&
        <div className="form-section">
              <h2>생활습관</h2>
              <label>흡연 여부:</label>
              <input type="radio" id="smoking_yes" name="smoking" value="yes" onChange={handleChange} />
              <label htmlFor="smoking_yes">예</label>
              <input type="radio" id="smoking_no" name="smoking" value="no" onChange={handleChange} />
              <label htmlFor="smoking_no">아니오</label>

              <label htmlFor="smoking_avg">현재 담배를 피운다면 하루 평균 (개피):</label>
              <input type="number" id="smoking_avg" name="smoking_avg" value={formData.smoking_avg} onChange={handleChange} />
          </div>
      }

          

          <div className="form-section">
              <h2>운동 습관</h2>
              <label>운동을 하십니까?</label>
              <input type="radio" id="exercise_yes" name="exercise" value="yes" onChange={handleChange} />
              <label htmlFor="exercise_yes">예</label>
              <input type="radio" id="exercise_no" name="exercise" value="no" onChange={handleChange} />
              <label htmlFor="exercise_no">아니오</label>

              <label htmlFor="exercise_freq">주당 운동 횟수:</label>
              <input type="number" id="exercise_freq" name="exercise_freq" value={formData.exercise_freq} onChange={handleChange} />
          </div>

          <div className="form-section">
              <h2>장애 여부</h2>
              <label>진행성 장애 여부:</label>
              <input type="radio" id="disability_yes" name="disability" value="yes" onChange={handleChange} />
              <label htmlFor="disability_yes">있음</label>
              <input type="radio" id="disability_no" name="disability" value="no" onChange={handleChange} />
              <label htmlFor="disability_no">없음</label>
          </div>

          <div className="form-section">
              <h2>기타</h2>
              <label htmlFor="comments">운동 프로그램에 바라는 점:</label>
              <textarea id="comments" name="comments" value={formData.comments} onChange={handleChange}></textarea>
          </div>

        {/* <input
          type="text"
          name="name"
          placeholder="이름"
          value={formData.name}
          onChange={handleChange}
          className="p-2 border rounded"
          required
        />
        <input
          type="email"
          name="email"
          placeholder="이메일"
          value={formData.email}
          onChange={handleChange}
          className="p-2 border rounded"
          required
        />
        <textarea
          name="feedback"
          placeholder="피드백을 입력해주세요..."
          value={formData.feedback}
          onChange={handleChange}
          className="p-2 border rounded"
          required
        /> */}
        { step < 5 ? (
          <button type="button" onClick={()=>{ nextStep()}} className="bg-blue-500 text-white p-2 rounded">
            다음
          </button>
        ) : (
          <button type="submit" className="bg-green-500 text-white p-2 rounded">
            제출하기
          </button>)
          }
          
        </form>
      </div>
    );
  };
